+import { join, resolve } from "@std/path";
+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+const isPlainObject = (value: unknown): value is Record<string, unknown> =>
+  typeof value === "object" && value !== null && !Array.isArray(value) &&
+  Object.getPrototypeOf(value) === Object.prototype;
+
+export function kebabToCamelCase(key: string): string {
+  return key.split(".").map((part) =>
+    part.replace(/-([a-zA-Z0-9])/g, (_, character: string) =>
+      character.toUpperCase()
+    )
+  ).join(".");
+}
+
+export function flattenConfig(
+  values: Record<string, unknown>,
+  prefix = "",
+): Record<string, unknown> {
+  const flattened: Record<string, unknown> = {};
+  for (const [key, value] of Object.entries(values)) {
+    const name = prefix ? `${prefix}.${kebabToCamelCase(key)}` : kebabToCamelCase(key);
+    if (isPlainObject(value)) {
+      Object.assign(flattened, flattenConfig(value, name));
+    } else {
+      flattened[name] = value;
+    }
+  }
+  return flattened;
+}
+
+export function parseRc(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const index = trimmed.indexOf("=");
+    if (index < 1) throw new Error(`Expected key=value pair: ${line}`);
+    const key = trimmed.slice(0, index).trim();
+    let value = trimmed.slice(index + 1).trim();
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length === 1) {
+        throw new Error(`Unterminated quoted value: ${line}`);
+      }
+      value = value.slice(1, -1);
+    } else if (value === "true" || value === "false") {
+      values[kebabToCamelCase(key)] = value === "true";
+      continue;
+    } else if (value !== "" && /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)(?:[eE][-+]?\\d+)?$/.test(value)) {
+      values[kebabToCamelCase(key)] = Number(value);
+      continue;
+    }
+    values[kebabToCamelCase(key)] = value;
+  }
+  return values;
+}
+
+function parseConfig(path: string, content: string, options: ConfigOptions): Record<string, unknown> {
+  try {
+    const values = options.parser
+      ? options.parser(content)
+      : path.endsWith(".rc")
+      ? parseRc(content)
+      : JSON.parse(content);
+    if (!isPlainObject(values)) throw new Error("Configuration must be a plain object.");
+    return flattenConfig(values);
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+function getRuntimeCwd(): string {
+  // dnt-shim-ignore
+  const { Deno, process } = globalThis as any;
+  if (Deno) return Deno.cwd();
+  if (process) return process.cwd();
+  throw new Error("unsupported runtime");
+}
+
+async function readTextFile(path: string): Promise<string | undefined> {
+  try {
+    // dnt-shim-ignore
+    const { Deno, process } = globalThis as any;
+    if (Deno) return await Deno.readTextFile(path);
+    if (process) return await (await import("node:fs/promises")).readFile(path, "utf8");
+    throw new Error("unsupported runtime");
+  } catch (error) {
+    if (error instanceof Error && (error.name === "NotFound" || (error as any).code === "ENOENT")) return;
+    throw error;
+  }
+}
+
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const paths = options.searchPaths?.length ? options.searchPaths : [getRuntimeCwd()];
+  const formats = options.formats?.length ? options.formats : [".json", ".rc"];
+  let foundPath: string | undefined;
+  const values: Record<string, unknown> = {};
+
+  for (const searchPath of paths) {
+    for (const format of formats) {
+      const filename = format === ".rc" ? `.${options.name}rc` : `${options.name}${format}`;
+      const path = resolve(join(searchPath, filename));
+      const content = await readTextFile(path);
+      if (typeof content === "undefined") continue;
+      const parsed = parseConfig(path, content, options);
+      foundPath ??= path;
+      if (!options.mergeConfigs) return { path, values: parsed };
+      // Earlier search paths have priority over later ones.
+      for (const [key, value] of Object.entries(parsed)) {
+        if (!(key in values)) values[key] = value;
+      }
+      break;
+    }
+  }
+  return { path: foundPath, values };
+}
